examples.content:
// Example 1: Simple Grid Layout
// This example demonstrates the basic grid layout system with a 2x2 grid
diagram {
    width: 400
    color: grey
    title: "Simple Grid Layout"
    top: Top
}

// The top-level box defines a 2x2 grid
box Top {
    grid: 2x2

    // Each box is positioned using (row, col) coordinates (1-based)
    // Box at position (1, 1) - top left
    box at (1, 1) is {
        color: red
        text: "Box A"
    }

    // Box at position (1, 2) - top right
    box at (1, 2) is {
        color: green
        text: "Box B"
    }

    // Box at position (2, 1) - bottom left
    box at (2, 1) is {
        color: blue
        text: "Box C"
    }

    // Box at position (2, 2) - bottom right
    box at (2, 2) is {
        color: yellow
        text: "Box D"
    }
}

// Example 2: Auto-Positioning
// Boxes without explicit "at" clauses are automatically positioned
// in the next available grid cell, scanning left-to-right, top-to-bottom
diagram {
    width: 500
    color: white
    title: "Auto-Positioning Demo"
    top: Top
}

box Top {
    grid: 3x3

    // First box auto-positions to (1, 1)
    box is {
        color: red
        text: "Auto 1"
    }

    // Second box auto-positions to (1, 2)
    box is {
        color: green
        text: "Auto 2"
    }

    // Explicitly position a box at (2, 2)
    box at (2, 2) is {
        color: blue
        text: "Fixed"
    }

    // Next auto-positioned box goes to (1, 3)
    box is {
        color: yellow
        text: "Auto 3"
    }

    // Auto-positions to (2, 1) - skips (2, 2) which is occupied
    box is {
        color: purple
        text: "Auto 4"
    }

    // Auto-positions to (2, 3)
    box is {
        color: cyan
        text: "Auto 5"
    }
}

// Example 16: Labels
// Labels are a convenient way to add text without creating full boxes
// They support multi-line text and optional positioning

diagram {
    width: 600
    color: white
    title: "Label Example"
    top: Top
}

box Top {
    grid: 2x3

    box is {
        color: green
        label "Green Box"
    }

    label "This is" "a label"

    box is {
        color: blue
        label "Blue Box"
    }

    label "This label is" "manually positioned" at (2, 3)

    label "This label is wide has has dimension 1x2" at (2, 1) dim 1x2
}

// Example 3: Box Dimensions
// The "dim" property allows boxes to span multiple grid cells
// Format: dim HEIGHTxWIDTH (e.g., dim 2x3 means 2 rows, 3 columns)
diagram {
    width: 600
    color: grey
    title: "Box Dimensions"
    top: Top
}

box Top {
    grid: 4x4

    // A box spanning 2 rows and 3 columns
    box at (1, 1) dim 2x3 is {
        color: red
        text: "Wide Box"
              "(2x3)"
    }

    // A tall box spanning 3 rows and 1 column
    box at (1, 4) dim 3x1 is {
        color: green
        text: "Tall"
              "Box"
              "(3x1)"
    }

    // A square box spanning 2x2
    box at (3, 1) dim 2x2 is {
        color: blue
        text: "Square"
              "(2x2)"
    }

    // Regular 1x1 boxes fill the remaining space
    box at (3, 3) is {
        color: yellow
        text: "1x1"
    }

    box at (4, 3) is {
        color: cyan
        text: "1x1"
    }

    box at (4, 4) is {
        color: orange
        text: "1x1"
    }
}

// Example 4: Nested Boxes
// Boxes can contain other boxes, creating hierarchical layouts
// Each box defines its own grid for positioning child boxes
diagram {
    width: 600
    color: white
    title: "Nested Boxes"
    top: Top
}

box Top {
    grid: 2x2

    // A parent box containing nested children
    box at (1, 1) is {
        color: red
        grid: 2x2

        // Child boxes within Parent A
        box at (1, 1) is {
            color: pink
            text: "Child A1"
        }

        box at (1, 2) is {
            color: pink
            text: "Child A2"
        }

        box at (2, 1) is {
            color: pink
            text: "Child A3"
        }

        box at (2, 2) is {
            color: pink
            text: "Child A4"
        }
    }

    // Another parent box with different nesting
    box at (1, 2) is {
        color: blue
        grid: 3x1

        box at (1, 1) is {
            color: cyan
            text: "Child B1"
        }

        box at (2, 1) is {
            color: cyan
            text: "Child B2"
        }

        box at (3, 1) is {
            color: cyan
            text: "Child B3"
        }
    }

    // Simple boxes without nesting
    box at (2, 1) is {
        color: green
        text: "Simple C"
    }

    box at (2, 2) is {
        color: yellow
        text: "Simple D"
    }
}

// Example 5: Reusable Box Definitions
// Define boxes once and reuse them multiple times
// This is useful for repeated components in your diagram
diagram {
    width: 700
    color: grey
    title: "Reusable Components"
    top: Top
}

// Define a reusable CPU core component
box CPUCore {
    grid: 3x2
    color: blue

    box at (1, 1) dim 1x2 is {
        text: "ALU"
    }

    label "L1-I" at (2, 1)
    label "L1-D" at (2, 2)

    box at (3, 1) dim 1x2 is {
        text: "Registers"
    }
}

// Define a reusable memory block
box MemoryBlock {
    grid: 2x1
    color: green

    label "Data" at (1, 1)
    label "Control" at (2, 1)
}

// Use the defined components in the main diagram
box Top {
    grid: 2x4

    // Instantiate CPUCore multiple times
    box at (1, 1) is CPUCore
    box at (1, 2) is CPUCore
    box at (1, 3) is CPUCore
    box at (1, 4) is CPUCore

    // Instantiate MemoryBlock multiple times
    box at (2, 1) is MemoryBlock
    box at (2, 2) is MemoryBlock
    box at (2, 3) is MemoryBlock
    box at (2, 4) is MemoryBlock
}

// Example 6: Multi-line Text
// Text can span multiple lines for better readability
// Each line is specified separately and will be rendered on its own line
diagram {
    width: 500
    color: white
    title: "Multi-line Text Demo"
    top: Top
}

box Top {
    grid: 2x2

    // Single-line text
    box at (1, 1) is {
        color: red
        text: "Single Line"
    }

    // Two-line text
    box at (1, 2) is {
        color: green
        text: "First Line"
              "Second Line"
    }

    // Three-line text
    box at (2, 1) is {
        color: blue
        text: "Line 1"
              "Line 2"
              "Line 3"
    }

    // Multi-line text with longer content
    box at (2, 2) is {
        color: yellow
        text: "Memory"
              "Controller"
              "Unit"
              "v2.0"
    }
}

// Example 7: Border Styles
// Boxes can have different border styles: solid, dotted, dashed, or none
// The default border style is solid
diagram {
    width: 600
    color: grey
    title: "Border Styles"
    top: Top
}

box Top {
    grid: 2x3

    // Default border (solid)
    box at (1, 1) is {
        color: white
        text: "Default"
              "(solid)"
    }

    // Explicit solid border
    box at (1, 2) is {
        color: white
        text: "Solid"
        borderStyle: solid
    }

    // Dotted border
    box at (1, 3) is {
        color: white
        text: "Dotted"
        borderStyle: dotted
    }

    // Dashed border
    box at (2, 1) is {
        color: white
        text: "Dashed"
        borderStyle: dashed
    }

    // No border (invisible box, useful for labels)
    box at (2, 2) is {
        color: white
        text: "No Border"
        borderStyle: none
    }

    // Combining border styles with colors
    box at (2, 3) is {
        color: cyan
        text: "Cyan"
              "Dotted"
        borderStyle: dotted
    }
}

// Example 8: Color Palette
// Demonstrates the available color options
// Supported colors: red, green, blue, yellow, purple, cyan, orange, pink, white, grey
diagram {
    width: 800
    color: white
    title: "Color Palette"
    top: Top
}

box Top {
    grid: 2x5

    box at (1, 1) is {
        color: red
        text: "Red"
    }

    box at (1, 2) is {
        color: green
        text: "Green"
    }

    box at (1, 3) is {
        color: blue
        text: "Blue"
    }

    box at (1, 4) is {
        color: yellow
        text: "Yellow"
    }

    box at (1, 5) is {
        color: purple
        text: "Purple"
    }

    box at (2, 1) is {
        color: cyan
        text: "Cyan"
    }

    box at (2, 2) is {
        color: orange
        text: "Orange"
    }

    box at (2, 3) is {
        color: pink
        text: "Pink"
    }

    box at (2, 4) is {
        color: white
        text: "White"
    }

    box at (2, 5) is {
        color: grey
        text: "Grey"
    }
}

// Example 9: System Architecture
// A practical example showing a computer system architecture
// Demonstrates nested boxes, dimensions, and reusable components
diagram {
    width: 800
    color: grey
    title: "Computer System Architecture"
    top: Top
}

// Define a processor core
box Processor {
    grid: 3x2
    color: blue

    box at (1, 1) dim 1x2 is {
        text: "Control Unit"
    }

    label "ALU" at (2, 1)
    label "FPU" at (2, 2)

    box at (3, 1) dim 1x2 is {
        text: "Cache L1"
    }
}

// Define a memory module
box Memory {
    grid: 2x1
    color: green

    label "RAM" at (1, 1)
    label "Controller" at (2, 1)
}

box Top {
    grid: 3x3

    // CPU section with two cores
    box at (1, 1) dim 2x2 is {
        grid: 1x2
        borderStyle: dashed

        box at (1, 1) is Processor
        box at (1, 2) is Processor
    }

    // Shared L2 Cache
    box at (1, 3) dim 2x1 is {
        color: cyan
        text: "L2 Cache"
              "Shared"
    }

    // Memory modules
    box at (3, 1) is Memory
    box at (3, 2) is Memory

    // I/O Controller
    box at (3, 3) is {
        color: yellow
        text: "I/O"
              "Controller"
    }
}

// Example 10: Network Topology
// Shows a network layout with routers, switches, and servers
// Demonstrates practical use of colors and labels
diagram {
    width: 700
    color: white
    title: "Network Topology"
    top: Top
}

// Define a server rack
box ServerRack {
    grid: 4x1
    color: blue

    label "Web" at (1, 1)
    label "App" at (2, 1)
    label "DB" at (3, 1)
    label "Cache" at (4, 1)
}

box Top {
    grid: 4x3

    // Internet gateway
    box at (1, 2) is {
        color: red
        text: "Internet"
              "Gateway"
    }

    // Core router
    box at (2, 2) is {
        color: orange
        text: "Core"
              "Router"
    }

    // Distribution switches
    box at (3, 1) is {
        color: yellow
        text: "Switch"
              "A"
    }

    box at (3, 2) is {
        color: yellow
        text: "Switch"
              "B"
    }

    box at (3, 3) is {
        color: yellow
        text: "Switch"
              "C"
    }

    // Server racks
    box at (4, 1) is ServerRack
    box at (4, 2) is ServerRack
    box at (4, 3) is ServerRack
}

// Example 11: Mixed Features
// Combines multiple features: auto-positioning, dimensions, nesting,
// reusable definitions, border styles, and multi-line text
diagram {
    width: 900
    color: grey
    title: "Mixed Features Demo"
    top: Top
}

// Reusable component with custom styling
box Module {
    grid: 2x2
    color: cyan
    borderStyle: dashed

    label "Input" at (1, 1)
    label "Process" at (1, 2)
    label "Output" at (2, 1)
    label "Control" at (2, 2)
}

box Top {
    grid: 4x6

    // Large header box spanning the width
    box at (1, 1) dim 1x6 is {
        color: blue
        text: "System Header"
        borderStyle: solid
    }

    // Explicitly positioned large box
    box at (2, 1) dim 2x2 is {
        color: red
        text: "Large"
              "Component"
              "(2x2)"
    }

    // Small boxes
    box at (2, 3) is {
        color: green
        text: "Small"
    }

    box at (2, 4) is {
        color: yellow
        text: "Small"
    }

    // Module instance
    box at (2, 5) dim 2x2 is Module

    // Label with no border
    box at (4, 1) dim 1x2 is {
        text: "Footer Label"
        borderStyle: none
    }

    // More boxes
    box at (3, 3) is {
        color: purple
        text: "Box"
    }

    box at (3, 4) is {
        color: orange
        text: "Box"
    }

    box at (4, 3) is {
        color: pink
        text: "Box"
    }

    box at (4, 4) is {
        color: cyan
        text: "Box"
    }
}

// Example 12: Microservice Architecture
// A comprehensive example showing a modern microservice system
// Demonstrates deep nesting, reusable components, and complex layouts
diagram {
    width: 1000
    color: white
    title: "Microservice Architecture"
    top: Top
}

// Define a microservice component
box Microservice {
    grid: 3x2
    color: blue

    box at (1, 1) dim 1x2 is {
        text: "API Gateway"
    }

    box at (2, 1) is {
        text: "Business"
              "Logic"
    }

    label "Cache" at (2, 2)

    box at (3, 1) dim 1x2 is {
        text: "Database"
    }
}

// Define a load balancer
box LoadBalancer {
    grid: 2x1
    color: orange

    label "LB" at (1, 1)

    box at (2, 1) is {
        text: "Health"
              "Check"
    }
}

box Top {
    grid: 5x4

    // Client layer
    box at (1, 1) dim 1x4 is {
        color: green
        text: "Client Applications"
        borderStyle: dashed
    }

    // Load balancer layer
    box at (2, 1) is LoadBalancer
    box at (2, 2) is LoadBalancer
    box at (2, 3) is LoadBalancer
    box at (2, 4) is LoadBalancer

    // Microservices layer
    box at (3, 1) is Microservice
    box at (3, 2) is Microservice
    box at (3, 3) is Microservice
    box at (3, 4) is Microservice

    // Message queue
    box at (4, 1) dim 1x4 is {
        color: purple
        text: "Message Queue / Event Bus"
    }

    // Monitoring and logging
    box at (5, 1) dim 1x2 is {
        color: yellow
        text: "Monitoring"
    }

    box at (5, 3) dim 1x2 is {
        color: cyan
        text: "Logging"
    }
}

// Example 13: Bold Text
// The bold property allows you to make text bold
// bold: true makes the text bold, bold: false (or omitting it) keeps it normal
// Note: bold cannot be used on boxes with child boxes
diagram {
    width: 600
    color: white
    title: "Bold Text Example"
    top: Top
}

box Top {
    grid: 2x3

    // Bold text
    box at (1, 1) is {
        color: red
        text: "Bold"
        bold: true
    }

    // Normal text (default)
    box at (1, 2) is {
        color: blue
        text: "Normal"
    }

    // Explicitly non-bold
    box at (1, 3) is {
        color: green
        text: "Not Bold"
        bold: false
    }

    // Bold multi-line text
    box at (2, 1) is {
        color: yellow
        text: "Bold"
              "Multi-line"
              "Text"
        bold: true
    }

    // Normal multi-line text
    box at (2, 2) is {
        color: purple
        text: "Normal"
              "Multi-line"
              "Text"
    }

    // Bold with different color
    box at (2, 3) is {
        color: cyan
        text: "Bold Cyan"
        bold: true
    }
}

// Example 14: Ports and Arrows
// Demonstrates how to define ports and connect them with arrows.
// Ports are positioned using fractional coordinates relative to the grid.
// Arrows automatically route between ports using orthogonal pathfinding (A* algorithm)
// to avoid obstacles (child boxes). This example shows an arrow routing around
// two boxes positioned in the grid.
diagram {
    width: 600
    color: white
    title: "Ports and Arrows"
}

box Top {
    grid: 3x3
    color: green

    box at (2, 1) is {
        color: red
        text : "A"
    }
    box at (2, 3) is {
        color: red
        text : "C"
    }

    port a at (0.0, 0.15)
    port b at (2.8, 2.9)

    arrow a to b
}

// Example 15: Circuit Block Diagram
// Demonstrates a complex circuit layout with multiple levels of nested boxes,
// ports, and arrows showing signal flow between components.
// This example shows how to create hierarchical block diagrams with automatic
// arrow routing between components at different nesting levels.

diagram {
    width: 1200
    color: white
    title: "Digital Signal Processor Architecture"
    cheatPorts: true
    top: Processor
}

box Processor {
    grid: 4x4

    port clock at (0.5, 0.0)

    arrow clock to core.clock
    arrow clock to io_interface.clock
    arrow clock to memory.clock

    // Input/Output Interface (top-left)
    box io_interface at (1, 1) is {
        grid: 2x2
        color: cyan

        port clock at (0.5, 0.0)

        box adc at (1, 1) is {
            text: "ADC"
            color: lime
        }

        box dac at (2, 1) is {
            text: "DAC"
            color: lime
        }
    }

    // Processing Core (center)
    box core at (2, 2) dim 1x1 is {
        grid: 3x2
        color: yellow

        port clock at (0.5, 0.0)

        box alu at (1, 1) is {
            text: "ALU"
            color: orange
        }

        box fpu at (2, 1) is {
            text: "FPU"
            color: orange
        }

        box control at (3, 1) dim 1x2 is {
            text: "Control\nUnit"
            color: pink
        }
    }

    // Memory Subsystem (top-right)
    box memory at (1, 3) dim 2x1 is {
        grid: 3x1
        color: teal

        port clock at (0.5, 0.0)
        box cache_l1 at (1, 1) is {
            text: "L1 Cache"
            color: cyan
        }

        box cache_l2 at (2, 1) is {
            text: "L2 Cache"
            color: cyan
        }

        box ram at (3, 1) is {
            text: "RAM"
            color: blue
        }
    }

    // DMA Controller (bottom-left)
    box dma at (3, 1) is {
        color: purple

        port dma_data at (0.0, 0.5)
        port dma_ctrl at (1.0, 0.5)

        arrow dma_data to dma_ctrl
    }

    // Clock and Power Management (bottom-center)
    box clock_power at (3, 2) is {
        grid: 3x3
        color: yellow

        box pll at (1, 1) is {
            text: "PLL"
            color: orange
        }

        box pmu at (2, 2) is {
            text: "PMU"
            color: orange
        }

        port irq_in at (0.0, 1.5)
        port irq_out at (3.0, 1.5)

        arrow irq_in to irq_out
    }

    // Interrupt Controller (bottom-right)
    box interrupt at (3, 3) is {
        color: pink
    }
}

// Example 17: Auto-Positioned Ports
// Ports can be automatically positioned on the sides of a box using the "on" clause
// Valid sides: top, bottom, left, right
// If neither "at" nor "on" is specified, ports default to the right side

diagram {
    width: 600
    color: white
    title: "Auto-Positioned Ports"
    top: Top
}

box Processor {
    grid: 2x2
    color: blue

    // Ports on different sides using "on" clause
    port clk on top
    port reset on top
    port data_in on left
    port data_out on right
    port status on bottom

    // Child box with its own ports
    box alu at (1, 1) is ALU

    // Connect parent port to child port
    arrow data_in to alu.input
    arrow alu.output to data_out
}

box ALU {
    grid: 2x2
    color: green

    // Ports with explicit positioning
    port input at (0.5, 0.0)

    // Auto-positioned port (defaults to right)
    port carry
}

box Top {
    grid: 3x3

    box cpu at (2, 2) is Processor

    // External ports that connect to the processor
    port ext_clk on top is {
        label "clock"
    }

    port ext_reset on top
    port ext_data on left
    port ext_status on bottom

    // Connect external ports to processor ports
    arrow ext_clk to cpu.clk
    arrow ext_reset to cpu.reset
    arrow ext_data to cpu.data_in
    arrow cpu.status to ext_status
}
